#include <iostream>
#include <vector>
using namespace std;
class Solution { public: vector<vector<int>> solve(vector<vector<int>>& graph) { vector<vector<int>> SCC; vector<int> visited(graph.size(), 0); for (int i = 0; i < graph.size(); i++) { if (!visited[i]) { DFS(graph, i, visited, SCC); } } return SCC; } void DFS(vector<vector<int>>& graph, int node, vector<int>& visited, vector<vector<int>>& SCC) { visited[node] = 1; for (int neighbor : graph[node]) { if (!visited[neighbor]) { DFS(graph, neighbor, visited, SCC); } } SCC.push_back({node}); } };

int main() {
    vector<vector<int>> graph = {{1, 2}, {0, 3}, {0, 3}, {}};
    Solution solver;
    vector<vector<int>> result = solver.solve(graph);
    for (auto component : result) {
        for (int node : component) {
            cout << node << ' '; 
        }
        cout << endl;
    }
    return 0;
}
